#include <stdio.h>
int find(int* parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

void unionSet(int* parent, int* rank, int x, int y) {
    int rootX = find(parent, x);
    int rootY = find(parent, y);
    if (rootX != rootY) {
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX;
        } else {
            parent[rootY] = rootX;
            rank[rootX]++;
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int k;
        scanf("%d", &k);
        int* parent = (int*)malloc(k * sizeof(int));
        int* rank = (int*)malloc(k * sizeof(int));
        for (int i = 0; i < k; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
        for (int i = 1; i < k; i++) {
            int p;
            scanf("%d", &p);
            unionSet(parent, rank, i, p);
        }
        int count = 0;
        for (int i = 0; i < k; i++) {
            if (parent[i] == i) {
                count++;
            }
        }
        printf("%d\n", count - 1);
        free(parent);
        free(rank);
    }
    return 0;
}

