t = int(input())
for _ in range(t):
    k = int(input())
    parent = [i for i in range(k)]
    rank = [0] * k
    roads = list(map(int, input().split()))
    for i in range(k - 1):
        unionSet(parent, rank, i + 1, roads[i])
    count = 0
    for i in range(k):
